    try:
        # Parse the JSON
        data = json.loads(complete_json_data)
        
        # Extract the trading records
        cached_json = data['CachedJson'][0]['value']
        records = json.loads(cached_json)
        
        print(f"📊 Found {len(records)} records to process")
        
        # Create the complete CSV
        output_file = 'complete_trading_rankings.csv'
        
        with open(output_file, 'w', newline='', encoding='utf-8') as csvfile:
            fieldnames = ['ranking', 'username', 'account_id']
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            
            # Write header
            writer.writeheader()
            
            # Write all records
            for record in records:
                ranking = record.get('ranking', '')
                nickname = record.get('nickname')
                username = nickname if nickname is not None else ''
                account_id = record.get('account_id', '')
                
                writer.writerow({
                    'ranking': ranking,
                    'username': username,
                    'account_id': account_id
                })
        
        print(f"✅ Successfully created {output_file} with {len(records)} records")
        
        # Verify the output
        with open(output_file, 'r') as f:
            line_count = sum(1 for line in f)
        
        print(f"📋 Verification: {line_count} total lines (including header)")
        print(f"📈 Data rows: {line_count - 1}")
        
        return output_file
        
    except Exception as e:
        print(f"❌ Error: {e}")
        return None

